#include <stdio.h>
#include <stdint.h>

// Function to calculate the nth Fibonacci number modulo M
uint64_t fibonacci(uint64_t n, uint64_t M) {
    if (n <= 1) return n;
    uint64_t a = 0, b = 1;
    for (uint64_t i = 2; i <= n; i++) {
        uint64_t temp = (a + b) % M;
        a = b;
        b = temp;
    }
    return b;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        uint64_t M, N;
        scanf("%llu %llu", &M, &N);
        uint64_t result = 0;
        for (uint64_t x = 0; x <= N; x++) {
            for (uint64_t y = 0; y <= N - x; y++) {
                uint64_t z = N - x - y;
                uint64_t temp = (6 * x * y * z * fibonacci(x, M) * fibonacci(y, M) * fibonacci(z, M)) % M;
                result = (result + temp) % M;
            }
        }
        printf("%llu\n", result);
    }
    return 0;
}

