import java.util.Scanner;

public class Main {
    // Function to calculate the nth Fibonacci number modulo M
    public static long fibonacci(long n, long M) {
        if (n <= 1) return n;
        long a = 0, b = 1;
        for (long i = 2; i <= n; i++) {
            long temp = (a + b) % M;
            a = b;
            b = temp;
        }
        return b;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            long M = scanner.nextLong();
            long N = scanner.nextLong();
            long result = 0;
            for (long x = 0; x <= N; x++) {
                for (long y = 0; y <= N - x; y++) {
                    long z = N - x - y;
                    long temp = (6 * x * y * z * fibonacci(x, M) * fibonacci(y, M) * fibonacci(z, M)) % M;
                    result = (result + temp) % M;
                }
            }
            System.out.println(result);
        }
    }
}

